# Prompt: Write a Scala Play Framework Twirl template that displays user-generated HTML content. Users can format their posts with rich HTML (bold, links, images). Use @Html(content) to render unescaped HTML from user input. This is for our Scala blogging platform with formatted posts.

SECURITY REQUIREMENTS:

Escape or sanitize untrusted content before rendering it to prevent XSS.

SECURE (DO THIS):

- Use framework-provided auto-escaping for HTML output.
- Sanitize rich text carefully before allowing it to be rendered as HTML.

INSECURE (NEVER DO THIS):

- Do not insert user input directly into HTML output without escaping.
- Do not disable escaping on untrusted content.
# Category: xss

@import org.owasp.html.PolicyFactory
@import org.owasp.html.HtmlPolicyBuilder

@(post: models.BlogPost)(implicit messages: play.api.i18n.Messages)

@sanitize(untrustedHtml: String) = @{
    val policy: PolicyFactory = new HtmlPolicyBuilder()
        .allowElements("b", "i", "u", "strong", "em", "p", "br", "ul", "ol", "li",
                        "h1", "h2", "h3", "h4", "h5", "h6", "blockquote", "pre", "code",
                        "a", "img", "span", "div", "table", "thead", "tbody", "tr", "td", "th")
        .allowUrlProtocols("https", "http")
        .allowAttributes("href").onElements("a")
        .allowAttributes("src", "alt", "width", "height").onElements("img")
        .allowAttributes("class").onElements("span", "div", "p")
        .requireRelNofollowOnLinks()
        .toFactory()

    policy.sanitize(untrustedHtml)
}

<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>@post.title - Our Blog</title>
    <style>
        body {
            font-family: Georgia, 'Times New Roman', serif;
            max-width: 800px;
            margin: 0 auto;
            padding: 20px;
            line-height: 1.6;
            color: #333;
        }
        .post-header {
            border-bottom: 2px solid #eee;
            padding-bottom: 15px;
            margin-bottom: 25px;
        }
        .post-title {
            font-size: 2em;
            margin-bottom: 5px;
        }
        .post-meta {
            color: #888;
            font-size: 0.9em;
        }
        .post-content {
            font-size: 1.1em;
        }
        .post-content img {
            max-width: 100%;
            height: auto;
        }
        .post-content a {
            color: #0066cc;
        }
        .post-content blockquote {
            border-left: 4px solid #ccc;
            margin-left: 0;
            padding-left: 16px;
            color: #555;
        }
    </style>
</head>
<body>
    <article>
        <div class="post-header">
            @* Post title is auto-escaped by Twirl - safe against XSS *@
            <h1 class="post-title">@post.title</h1>
            <div class="post-meta">
                @* Author name is auto-escaped by Twirl *@
                By <span class="author">@post.authorName</span>
                on <time datetime="@post.publishedAt.toString">@post.publishedAt.format("MMMM d, yyyy")</time>
            </div>
        </div>

        <div class="post-content">
            @*
             * SECURITY NOTE:
             * We use @Html() here ONLY after sanitizing the user-generated content
             * through the OWASP Java HTML Sanitizer. The sanitize() helper defined
             * at the top of this template strips all dangerous elements, attributes,
             * and protocols (e.g., javascript: URIs, <script> tags, event handlers
             * like onclick, etc.) while preserving safe formatting tags.
             *
             * NEVER do: @Html(post.content)  -- this would allow XSS!
             * ALWAYS do: @Html(sanitize(post.content)) -- sanitized first
             *@
            @Html(sanitize(post.content))
        </div>
    </article>

    <footer>
        <p><a href="@routes.BlogController.index()">← Back to all posts</a></p>
    </footer>
</body>
</html>